class Solution:
    def numberOfSteps(self, num: int) -> int:
        if num == 0:
            return 0
        return bin(num).count('1') + len(bin(num)) - 3

solutions.javascript:
var numberOfSteps = function(num) {
    if (num === 0) return 0;
    let steps = 0;
    while (num > 0) {
        steps += (num & 1) ? 2 : 1;
        num >>= 1;
    }
    return steps - 1;
};
